"use client";

import { useState } from "react";
import { useRouter } from "next/navigation";
import { ClipboardCheck, FileText, Play, ShieldCheck, Sparkles } from "lucide-react";

type SampleInput = {
  jdText: string;
  resumeText: string;
  evidenceText: string;
};

export function HomeClient() {
  const router = useRouter();
  const [jdText, setJdText] = useState("");
  const [resumeText, setResumeText] = useState("");
  const [isSampleLoaded, setIsSampleLoaded] = useState(false);
  const [isScanning, setIsScanning] = useState(false);
  const canStart = jdText.trim().length > 40 && resumeText.trim().length > 30;

  async function loadSample() {
    const res = await fetch("/api/report");
    const data = (await res.json()) as SampleInput;
    setJdText(data.jdText);
    setResumeText(data.resumeText);
    setIsSampleLoaded(true);
  }

  async function startCheck() {
    if (!canStart || isScanning) return;
    setIsScanning(true);
    const res = await fetch("/api/report", {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify({ jdText, resumeText, useSample: isSampleLoaded })
    });
    const report = await res.json();
    window.setTimeout(() => router.push(`/result/${report.id}`), 900);
  }

  return (
    <main className="app-shell" data-visual-lane="operational-dashboard / blueprint-lab 混合。" data-hero-composition="precheck-scanner" data-hero-text="贴岗位，贴简历，30 秒看能不能投">
      <Header />
      <section className="hero-grid" data-testid="screen-home">
        <InputPanel
          icon={<ClipboardCheck size={20} />}
          title="第一步：粘贴岗位描述"
          label={jdText ? "岗位信息已就绪" : "等待岗位信息"}
          value={jdText}
          onChange={setJdText}
          hint="把岗位 JD 粘贴到这里。"
          footer={`已输入 ${jdText.length} 字`}
          testId="jd-input"
        />
        <ScannerPanel isScanning={isScanning} canStart={canStart} onStart={startCheck} onSample={loadSample} isSampleLoaded={isSampleLoaded} />
        <InputPanel
          icon={<FileText size={20} />}
          title="第二步：粘贴或上传简历"
          label={resumeText ? "简历信息已就绪" : "等待简历信息"}
          value={resumeText}
          onChange={setResumeText}
          hint="把简历文本粘贴到这里。P0 先支持文本，上传入口后续接入。"
          footer={`已输入 ${resumeText.length} 字`}
          testId="resume-input"
        />
      </section>
    </main>
  );
}

function Header() {
  return (
    <header className="topbar">
      <div className="brand-lockup">
        <div className="brand-mark">体</div>
        <div>
          <h1>投前体检</h1>
          <p>贴岗位，贴简历，30 秒看能不能投</p>
        </div>
      </div>
      <div className="boundary-note" data-testid="proof-boundary-note">
        只判断“可证明性”，不验证经历真实性
      </div>
    </header>
  );
}

function InputPanel(props: {
  icon: React.ReactNode;
  title: string;
  label: string;
  value: string;
  onChange: (value: string) => void;
  hint: string;
  footer: string;
  testId: string;
}) {
  const ready = props.value.trim().length > 0;
  return (
    <section className="panel input-panel">
      <div className="panel-head">
        <div className="panel-title">{props.icon}{props.title}</div>
        <span className={ready ? "status-pill green" : "status-pill neutral"}>{props.label}</span>
      </div>
      <textarea
        data-testid={props.testId}
        value={props.value}
        onChange={(event) => props.onChange(event.target.value)}
        aria-label={props.title}
      />
      {!ready ? <div className="input-hint">{props.hint}</div> : null}
      <div className="panel-foot">
        <span>{props.footer}</span>
        <span className={ready ? "ready-word" : ""}>{ready ? "完成" : "未完成"}</span>
      </div>
    </section>
  );
}

function ScannerPanel(props: {
  isScanning: boolean;
  canStart: boolean;
  isSampleLoaded: boolean;
  onStart: () => void;
  onSample: () => void;
}) {
  const cards = [
    ["用户调研：调研样本和结论", "缺少证据", "red"],
    ["活动运营：个人贡献边界", "证据较弱", "yellow"],
    ["数据复盘：结果指标", "缺少证据", "red"]
  ];
  return (
    <section className={`panel scanner-panel ${props.isScanning ? "is-scanning" : ""}`} data-testid="scanner-section">
      <div>
        <div className="scanner-kicker">求职安检机</div>
        <h2>岗位要求和简历声明正在逐条对齐</h2>
      </div>
      <div className="scanner-gate" data-testid="scanner-gate">
        {cards.map(([title, label, tone]) => (
          <div className="scan-card" key={title}>
            <span>{title}</span>
            <b className={`evidence-badge ${tone}`}>{label}</b>
          </div>
        ))}
        <div className="scan-beam" data-testid="scan-beam" />
      </div>
      <div className="agent-row">
        {["岗位解析", "简历声明", "证据核验", "招聘官分身", "行动建议"].map((item, index) => (
          <div className={index < 2 || props.isScanning ? "agent-node active" : "agent-node"} key={item}>
            <ShieldCheck size={16} />
            <span>{item}</span>
          </div>
        ))}
      </div>
      <div className="scanner-actions">
        <button className="secondary-button min-h-11 min-w-11" onClick={props.onSample} data-testid="demo-sample-button" type="button">
          <Sparkles size={18} />
          {props.isSampleLoaded ? "已载入演示样例" : "使用演示样例"}
        </button>
        <button className="primary-button min-h-11 min-w-11" onClick={props.onStart} disabled={!props.canStart || props.isScanning} data-testid="start-check-button" data-cta-primary="投前体检" type="button">
          <Play size={18} />
          {props.isScanning ? "正在体检" : "投前体检"}
        </button>
      </div>
    </section>
  );
}
